    def __init__(self):
        pass

    def add(self, x, y):
        return x + y

    def subtract( self, x, y):
        return x - y

    def multiply(self, x, y):
        return x * y

    def divide(self, x, y):
        if y == 0:
            return "Error: Division by zero"
        return x / y

    def power(self, x, y):
        return x ** y

    def log(self, x, base):
        if x <= 0 or base <= 0 or base == 1:
            return "Error: Invalid input for logarithm"
        return math.log(x, base)

    def factorial(self, n):
        if not isinstance(n, int) or n < 0:
            return "Error: Invalid input for factorial"
        if n == 0:
            return 1
        else:
            result = 1
            for i in range(1, n + 1):
                result *= i
            return result

    def sin(self, x):
        return math.sin(x)

    def cos(self, x):
        return math.cos(x)

    def tan(self, x):
        return math.tan(x)

    def sqrt(self, x):
        if x < 0:
            return "Error: Invalid input for square root"
        return math.sqrt(x)

    def nth_root(self, x, n):
        if n == 0:
            return "Error: Cannot take 0th root"
        if x < 0 and n % 2 == 0:
            return "Error: Cannot take even root of negative number"
        return x ** (1/n)

    def arcsin(self, x):
        if not -1 <= x <= 1:
            return "Error: Invalid input for arcsin"
        return math.asin(x)

    def arccos(self, x):
        if not -1 <= x <= 1:
            return "Error: Invalid input for arccos"
        return math.acos(x)

    def arctan(self, x):
        return math.atan(x)

