            if current_text == "0" or current_text == "Error":
                self.result_var.set(text)
            else:
                self.result_var.set(current_text + text)

    def open_log_dialog(self):
        dialog = tk.Toplevel(self.master)
        dialog.title("Logarithm Base")

        base_label = ttk.Label(dialog, text="Enter Base:")
        base_label.grid(row=0, column=0, padx=5, pady=5)

        base_entry = ttk.Entry(dialog)
        base_entry.grid(row=0, column=1, padx=5, pady=5)

        def calculate_log():
            try:
                base = float(base_entry.get())
                value = float(self.result_var.get())
                result = math.log(value, base)
                self.result_var.set(str(result))
                dialog.destroy()
            except Exception as e:
                messagebox.showerror("Error", f"Invalid Input for Logarithm: {e}")
                self.result_var.set("Error")
                dialog.destroy()

        calculate_button = ttk.Button(dialog, text="Calculate", command=calculate_log)
        calculate_button.grid(row=1, column=0, columnspan=2, padx=5, pady=5)

